import { useEffect, useState } from "react";
import { useParams } from "react-router-dom";
import API from "../services/api";
import "../styles/MatchDetails.css";

function MatchDetails() {
  const { id } = useParams();
  const [match, setMatch] = useState(null);
  const [loading, setLoading] = useState(true);
  const [activeTeam, setActiveTeam] = useState(null);
  const [availablePlayers, setAvailablePlayers] = useState([]);
  const [selectedPlayer, setSelectedPlayer] = useState(null);
  const [playerStats, setPlayerStats] = useState({
    runs: 0,
    wickets: 0,
    ballsFaced: 0,
    strikeRate: 0,
    battingAvg: 0
  });
  const [error, setError] = useState("");

  useEffect(() => {
    const fetchMatchDetails = async () => {
      try {
        const res = await API.get(`/matches/${id}`);
        setMatch(res.data);
      } catch (error) {
        console.error("Error fetching match details:", error);
      } finally {
        setLoading(false);
      }
    };

    fetchMatchDetails();
  }, [id]);

  const fetchPlayersByTeam = async (team) => {
    try {
      console.log("Fetching players for team:", team);
      const res = await API.get(`/players/team/${team}`);
      console.log("Players fetched:", res.data);
      setAvailablePlayers(res.data);
      setActiveTeam(team);
      setSelectedPlayer(null);
      setError("");
    } catch (err) {
      console.error("Error fetching players:", err);
      setError(`Failed to load players: ${err.response?.data?.message || err.message}`);
    }
  };

  const handlePlayerStatsChange = (e) => {
    const { name, value } = e.target;
    setPlayerStats({
      ...playerStats,
      [name]: name === 'strikeRate' || name === 'battingAvg' ? parseFloat(value) || 0 : parseInt(value) || 0
    });
  };

  const handleAddPlayer = async () => {
    if (!selectedPlayer) {
      setError("Please select a player");
      return;
    }

    const playerData = {
      playerId: selectedPlayer._id,
      name: selectedPlayer.name,
      team: selectedPlayer.team,
      role: selectedPlayer.role,
      runs: playerStats.runs,
      wickets: playerStats.wickets,
      ballsFaced: playerStats.ballsFaced,
      strikeRate: playerStats.strikeRate,
      battingAvg: playerStats.battingAvg
    };

    try {
      const updatedPlayers = [...(match.players || []), playerData];
      const res = await API.put(`/matches/${id}`, { ...match, players: updatedPlayers });
      setMatch(res.data);
      setSelectedPlayer(null);
      setPlayerStats({ runs: 0, wickets: 0, ballsFaced: 0, strikeRate: 0, battingAvg: 0 });
      setError("");
      alert("Player added successfully!");
    } catch (err) {
      setError("Failed to add player");
      console.error(err);
    }
  };

  const handleRemovePlayer = async (index) => {
    try {
      const updatedPlayers = match.players.filter((_, i) => i !== index);
      const res = await API.put(`/matches/${id}`, { ...match, players: updatedPlayers });
      setMatch(res.data);
      alert("Player removed successfully!");
    } catch (err) {
      setError("Failed to remove player");
      console.error(err);
    }
  };

  if (loading) return <p>Loading...</p>;
  if (!match) return <p>Match not found</p>;

  const teamAPlayers = match.players?.filter(p => p.team === match.teamA) || [];
  const teamBPlayers = match.players?.filter(p => p.team === match.teamB) || [];

  const PlayerStats = ({ player, onRemove }) => (
    <div className="player-stat-card">
      <div className="player-header">
        <div>
          <h4>{player.name}</h4>
          <p className="player-role">{player.role}</p>
        </div>
        <button onClick={onRemove} className="remove-player-btn">×</button>
      </div>
      <div className="stats-grid">
        <div className="stat">
          <span className="stat-label">Runs</span>
          <span className="stat-value">{player.runs}</span>
        </div>
        <div className="stat">
          <span className="stat-label">Avg</span>
          <span className="stat-value">{player.battingAvg.toFixed(2)}</span>
        </div>
        <div className="stat">
          <span className="stat-label">SR</span>
          <span className="stat-value">{player.strikeRate.toFixed(2)}</span>
        </div>
        <div className="stat">
          <span className="stat-label">Wickets</span>
          <span className="stat-value">{player.wickets}</span>
        </div>
      </div>
    </div>
  );

  return (
    <div className="match-details-page">
      <div className="match-header">
        <h2>{match.teamA} <span className="vs">vs</span> {match.teamB}</h2>
        <div className="match-score">
          <div className="team-score">
            <p className="team-name">{match.teamA}</p>
            <p className="score">{match.scoreA}</p>
          </div>
          <div className="team-score">
            <p className="team-name">{match.teamB}</p>
            <p className="score">{match.scoreB}</p>
          </div>
        </div>
        <div className="match-info">
          <p><strong>Overs:</strong> {match.overs}</p>
          <p><strong>Status:</strong> <span className={`status ${match.status}`}>{match.status}</span></p>
        </div>
      </div>

      <div className="teams-players">
        <div className="team-section">
          <h3>{match.teamA}</h3>
          <div className="players-grid">
            {teamAPlayers.length > 0 ? (
              teamAPlayers.map((player, idx) => (
                <PlayerStats key={idx} player={player} onRemove={() => handleRemovePlayer(idx)} />
              ))
            ) : (
              <p className="no-players">No players added</p>
            )}
          </div>
          <button 
            onClick={() => {
              console.log("Add player button clicked for:", match.teamA);
              fetchPlayersByTeam(match.teamA);
            }}
            className="add-player-btn"
          >
            + Add Player to {match.teamA}
          </button>
        </div>

        <div className="team-section">
          <h3>{match.teamB}</h3>
          <div className="players-grid">
            {teamBPlayers.length > 0 ? (
              teamBPlayers.map((player, idx) => (
                <PlayerStats key={idx} player={player} onRemove={() => handleRemovePlayer(teamAPlayers.length + idx)} />
              ))
            ) : (
              <p className="no-players">No players added</p>
            )}
          </div>
          <button 
            onClick={() => fetchPlayersByTeam(match.teamB)}
            className="add-player-btn"
          >
            + Add Player to {match.teamB}
          </button>
        </div>
      </div>

      {activeTeam && (
        <div className="add-player-form-overlay">
          <div className="add-player-form">
            <h3>Add Player to {activeTeam}</h3>
            {error && <p className="error-msg">{error}</p>}

            <div className="input-group">
              <label>Select Player</label>
              {availablePlayers.length === 0 ? (
                <p style={{ color: '#dc3545', fontSize: '14px', margin: '10px 0 0 0' }}>
                  No players found for {activeTeam}. Please create players first.
                </p>
              ) : (
                <select 
                  value={selectedPlayer?._id || ""} 
                  onChange={(e) => {
                    const player = availablePlayers.find(p => p._id === e.target.value);
                    setSelectedPlayer(player || null);
                  }}
                >
                  <option value="">Choose a player from {activeTeam}</option>
                  {availablePlayers.map(player => (
                    <option key={player._id} value={player._id}>
                      {player.name} ({player.role})
                    </option>
                  ))}
                </select>
              )}
            </div>

            {selectedPlayer && (
              <div className="player-stats-grid">
                <div className="input-group">
                  <label>Runs</label>
                  <input type="number" name="runs" value={playerStats.runs} onChange={handlePlayerStatsChange} min="0" />
                </div>
                <div className="input-group">
                  <label>Wickets</label>
                  <input type="number" name="wickets" value={playerStats.wickets} onChange={handlePlayerStatsChange} min="0" />
                </div>
                <div className="input-group">
                  <label>Balls Faced</label>
                  <input type="number" name="ballsFaced" value={playerStats.ballsFaced} onChange={handlePlayerStatsChange} min="0" />
                </div>
                <div className="input-group">
                  <label>Strike Rate</label>
                  <input type="number" name="strikeRate" value={playerStats.strikeRate} onChange={handlePlayerStatsChange} step="0.01" min="0" />
                </div>
                <div className="input-group">
                  <label>Batting Avg</label>
                  <input type="number" name="battingAvg" value={playerStats.battingAvg} onChange={handlePlayerStatsChange} step="0.01" min="0" />
                </div>
              </div>
            )}

            <div className="form-buttons">
              <button onClick={handleAddPlayer} className="add-btn">Add Player</button>
              <button onClick={() => setActiveTeam(null)} className="cancel-btn">Cancel</button>
            </div>
          </div>
        </div>
      )}
    </div>
  );
}

export default MatchDetails;
